var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"가람아.","JPN":"ヒカリ。","ENG":"Garam.","TWN":"嘉蘭。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"관둔다면서……? 회사…… 아카데미도.","JPN":"やめるの……？　会社……アカデミーも。","ENG":"I heard you were quitting... The company... and the Academy.","TWN":"聽說你要辭職……？公司……還有學院。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저 같은 사람, 누가 원하겠어요?","JPN":"だって私みたいな人間はどこからも歓迎されませんから。","ENG":"Who would want someone like me?","TWN":"像我這樣的人，誰會想要呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……결국 선배가 옳았어요.","JPN":"……結局、先輩が正しかったです。","ENG":"...In the end, you were right.","TWN":"……結果還是前輩說得對。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"제가 지금까지 이뤄낸 것들은 전부 선배가 곁에 있어 준 덕이었어요.","JPN":"私が今まで成し遂げたことはすべて、先輩が側にいてくれたからできたことです。","ENG":"Everything that I have accomplished until now was because you were there with me.","TWN":"我至今取得的所有成就，都是因為有前輩在我身邊。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"전…… 그게 제 능력이라고 생각했죠.","JPN":"私は……それが自分の能力なんだと勘違いしてました。","ENG":"And I... foolishly thought that it was my abilities.","TWN":"我……以為那就是我的能力。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이번 사고도 모두가 아니었으면 해결하지 못했을 거예요.","JPN":"今回の事故も、皆の力がなければ解決できなかったはずです。","ENG":"Even this incident couldn't have been resolved without everyone's help.","TWN":"這次事故如果沒有大家的幫助，是無法解決的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……그렇지 않아.","JPN":"……そんなことない。","ENG":"...That's not true.","TWN":"……不是這樣的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"힘들었을 거야…… 네가 없었으면.","JPN":"難しかったと思う……ヒカリがいなかったら。","ENG":"It would've been difficult... if you weren't there.","TWN":"一定會很辛苦……要是沒有你。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"받으러 가는 거지……? 조사. 관리국에.","JPN":"受けに行くんだよね……？　調査……管理局に。","ENG":"You're going to the Administration...? For questioning.","TWN":"要去管理局接受調查？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네. 아티팩트와 관련된 사고니까요. 유저들의 소송 건도 있고요.","JPN":"はい。アーティファクト関連の事故ですから。ユーザーの訴訟もありますし。","ENG":"Yes. It was an Artifact-related incident after all. And there are lawsuits from the players as well.","TWN":"是的，與神器相關的事故，還有玩家的訴訟案件。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"도와줄게…… 내가 할 수 있는 일이 있다면.","JPN":"力を貸すよ……私にできることがあれば。","ENG":"I'll help... With whatever I can.","TWN":"我會幫你的……只要是我能做的事。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……이만 가볼게요. 더 이상 선배 얼굴을 못 보겠어요.","JPN":"……そろそろ行きますね。これ以上先輩の顔を見ているのも辛いので。","ENG":"...I best get going. I'm too ashamed to even look at your face right now.","TWN":"……我先走了，我已經沒臉見前輩你了。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"지금까지 정말 고마웠어요.","JPN":"今までありがとうございました。","ENG":"Thank you for everything.","TWN":"一直以來真的謝謝你。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……아니.","JPN":"……ううん。","ENG":"...No.","TWN":"……不。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"이런 식의 이별은…… 이제 싫어.","JPN":"こんな別れは……もういやだ。","ENG":"I don't like... these kinds of goodbyes.","TWN":"這樣的離別……我已經受夠了。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배……?","JPN":"先輩……","ENG":"Naielle...","TWN":"前輩……？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"찾아와…… 조사 끝나면.","JPN":"会いに来て……調査が終わったら。","ENG":"Come back... once the investigation is over.","TWN":"調查結束後……來找我。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아니면…… 내가 찾아갈 테니까.","JPN":"来ないと……私が会いに行くから。","ENG":"Or... I'll come find you.","TWN":"不然……我去找你吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"미안해요 선배…… 선배를 다시 보진 못할 것 같아요.","JPN":"ごめんなさい、先輩……もう先輩に会うことはないと思います。","ENG":"I'm sorry, Bora... but I don't think we'll be seeing each other again.","TWN":"對不起，前輩……我可能再也見不到你了。"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……더는 이 일을 하지 못할 테니까요.","JPN":"……この仕事はもうできないから。","ENG":"...Because I won't be able to do this kind of work anymore.","TWN":"……我不能再做這件事了。"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"조사가 끝나면 전 고향에 내려가서…….","JPN":"調査が終わったら、故郷に帰って……","ENG":"I'm going to head back home once the investigation is done…","TWN":"調查結束後，我要回老家……"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아얏!","JPN":"いたっ！","ENG":"Ouch!","TWN":"哎呀！"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"어이쿠! 죄송합니다. 괜찮으신가요?","JPN":"おっと！　すみません。大丈夫ですか？","ENG":"Oh! I'm sorry. Are you all right?","TWN":"啊，對不起！你沒事吧？"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"CHEOLSU_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"괘, 괜찮아요.","JPN":"だ、大丈夫です。","ENG":"I-I'm okay.","TWN":"你，你沒事吧？"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"어라? 그 복장은 혹시, 샐러리맨X……?!","JPN":"あれ？　その格好はもしかして、サラリーマンX……！？","ENG":"Huh? That outfit. Are you... Salaryman X...?!","TWN":"咦？那身裝扮，難道是上班族X……？"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};